#include<bits/stdc++.h>
using namespace std;
int n,m,p,q,fa[1000010],col[1000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
int main()
{
    scanf("%d%d%d%d",&n,&m,&p,&q);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(int i=m;i>=1;i--)
    {
		int l=(i*p+q)%n+1;
		int r=(i*q+p)%n+1;
		if(l>r)
        {
            swap(l,r);
        }
        for(int j=r;j>=l;j=fa[j])
        {
            if(j==find(j))
            {
                col[j]=i;
                fa[j]=find(j-1);
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",col[i]);
    }
    return 0;
}
